import React from 'react';
import { clsx } from 'clsx';
import { useScrollReveal } from '../hooks';
import { scrollToSection, PRICING_FEATURES, COMPANY_INFO } from '../utils';
import { SectionHeader, Button, Icon } from './ui';

const Pricing = () => {
  const [ref, isVisible] = useScrollReveal();

  return (
    <section className="section" id="pricing">
      <div className="container">
        <SectionHeader
          number="03"
          title="One"
          titleHighlight="Simple"
          description="Simple, transparent pricing. Just secure, professional storage for your most important documents."
        />

        <div
          ref={ref}
          className={clsx(
            'max-w-[520px] mx-auto opacity-0 translate-y-10 transition-all duration-700 ease-out-expo',
            isVisible && 'opacity-100 translate-y-0'
          )}
        >
          <div className="bg-primary text-white rounded-[32px] p-16 text-center relative overflow-hidden group">
            {/* Hover Border Effect */}
            <div className="absolute -top-0.5 -left-0.5 -right-0.5 -bottom-0.5 bg-gradient-to-br from-gold via-transparent to-gold rounded-[34px] -z-10 opacity-0 transition-opacity duration-500 group-hover:opacity-50" />

            {/* Badge */}
            <span className="inline-block bg-gold text-primary px-5 py-2 rounded-full text-[11px] font-semibold tracking-[0.1em] uppercase mb-8">
              Opening Promo
            </span>

            {/* Title */}
            <h3 className="font-serif text-2xl italic text-white/70 mb-4">
              Will Storage Service
            </h3>

            {/* Price */}
            <div className="flex items-baseline justify-center gap-1 mb-2">
              <span className="text-3xl text-gold">$</span>
              <span className="text-8xl font-medium leading-none tracking-tight">
                {COMPANY_INFO.price}
              </span>
            </div>
            <p className="text-sm text-white/40 mb-2">per year • Opening promo</p>
            <p className="text-xs text-white/30 mb-12">${COMPANY_INFO.priceAfterPromo}/year after first year</p>

            {/* Features */}
            <ul className="text-left mb-12 space-y-0">
              {PRICING_FEATURES.map((feature, index) => (
                <li
                  key={index}
                  className="flex items-center gap-4 py-4 border-b border-white/[0.08] text-[15px] text-white/70 transition-all duration-300 hover:pl-2 hover:text-white last:border-b-0"
                >
                  <Icon name="check" size={18} strokeWidth={2.5} className="text-gold shrink-0" />
                  {feature}
                </li>
              ))}
            </ul>

            {/* CTA */}
            <Button
              href="#contact"
              variant="gold"
              icon
              className="w-full justify-center"
              onClick={(e) => scrollToSection(e, 'contact')}
            >
              Get Started Now
            </Button>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Pricing;
